class Solution:
    def prefixConnected(self, words: List[str], k: int) -> int:
        from collections import Counter
        counts = Counter()
        for w in words:
            if len(w) >= k:
                counts[w[:k]] += 1
        return sum(1 for v in counts.values() if v >= 2)

