var prefixConnected = function(words, k) {
    const counts = new Map();
    for (const w of words) {
        if (w.length >= k) {
            const p = w.slice(0, k);
            counts.set(p, (counts.get(p) || 0) + 1);
        }
    }
    let total = 0;
    for (const v of counts.values()) {
        if (v >= 2) total++;
    }
    return total;
};
